INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '12379d0a-b93e-4b13-92e3-d537b6b8401b',
  '00000000-0000-0000-0000-000000000001',
  $escape$ebpf: Leverage WebAssembly for System Access with WASI and Sandbox$escape$,
  $escape$ebpf programs interact with the Linux kernel's system call interface, but what if you need to access system resources outside of this interface? WebAssembly (WASM) provides a sandboxed execution environment for system calls, which can be leveraged using the WebAssembly System Interface (WASI). By using WASI, your ebpf programs can access system resources such as files, sockets, and processes, without compromising the secure execution environment of the kernel. This is achieved by mapping the system call entry points to the WASI interface, allowing ebpf programs to make system calls through the WASI API.$escape$,
  NULL,
  NULL,
